	(16, 1, 'pdp_30_inv_', 'ta', 'custom', '[]', 1, '2026-04-23 22:24:41.000', '2026-04-24 00:12:04.000', '*PDP நிறுவனரின் 30வது ஆண்டு நிறுவனர் தின விழா இலவச மருத்துவ முகாம் மற்றும் நலத்திட்டங்கள் வழங்கும் விழா*\n\nஎங்கள் தாய் தந்தையர்கள் தெய்வதிரு P.துரைப்பாண்டி நாடார், தெய்வதிருமதி D.சரோஜா அம்மாள் அவர்களின் நல்லாசியுடன், கல்வி மற்றும் மருத்துவ தொண்டு அறக்கட்டளை சார்பில், பல்வேறு நோய்களுக்கு சிகிச்சை அளிக்கும் இலவச மருத்துவ முகாமும், நலதிட்ட உதவிகள் வழங்கும் விழாவும் நடத்த ஏற்பாடு செய்யபட்டுள்ளது. இந்த நிகழ்வில் கலந்து கொள்ள அன்புடன் அழைக்கிறோம்..\n\nநாள்    : 14-8-2025, வியாழக்கிழமை\nநேரம்  : காலை 9.00 மணி\nஇடம்   : T.பாலசுகுமார் கல்யாண மஹால், திசையன்விளை.', '[]', 'Powered by Duresh Tech', 'TEXT', 'THOOYAVAN PDP CABLE TV', 'ACTIVE', '1086147316362659'),
	(17, 1, 'pdp_ctv_biometric_attandance', 'en', 'custom', '["1", "2", "3"]', 1, '2026-04-23 22:24:41.000', '2026-04-24 00:12:04.000', 'Dear *{{1}}*, your *{{2}}* at *{{3}}* is recorded via biometric.', '[]', 'THOOYAVAN PDP CABLE TV', NULL, NULL, 'ACTIVE', '1329895772138100'),
